import type { RangeItem } from './range-legend.js';
export type LabelAlignment = 'start' | 'center' | 'end';
export interface SegmentPositionAndSize {
    itemHeight: number;
    itemWidth: number;
    itemX: number;
    itemY: number;
}
export interface InternalRangeItem extends RangeItem {
    labels: Record<'from' | 'to', string>;
}
/**
 * Coordinates of a label relative to the SVG container.
 */
export interface LabelCoords {
    x?: number;
    y?: number;
}
/**
 * Coordinates of a label relative to the SVG container.
 */
export interface HorizontalCoords {
    start: number;
    end: number;
}
export type RangeLabel = LabelCoords & {
    text: string;
};
